/**
 * pages/Inventory.jsx — Stock management with reorder alerts and category filter.
 */
import { useState, useEffect } from 'react';
import { inventoryAPI } from '../api/endpoints';
import toast from 'react-hot-toast';
import Badge from '../components/Badge';

const INR = (v) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(v);

const CATEGORIES = ['All', 'Bottles', 'Feed', 'Medicine', 'Equipment', 'Packaging', 'Chemicals', 'Other'];

const CAT_ICON = {
  All:       '📦',
  Bottles:   '🍶',
  Feed:      '🌾',
  Medicine:  '💊',
  Equipment: '🔧',
  Packaging: '📫',
  Chemicals: '🧪',
  Other:     '📋',
};

// Fixed bottle groups — order & labels are product-defined
const BOTTLE_GROUPS = [
  {
    product: 'Milk',
    icon: '🥛',
    color: 'blue',
    sizes: [
      { label: '1 Litre',  code: 'BTL-MILK-1L'    },
      { label: '500 ml',   code: 'BTL-MILK-500ML'  },
    ],
  },
  {
    product: 'Ghee',
    icon: '🧈',
    color: 'yellow',
    sizes: [
      { label: '1 Litre',  code: 'BTL-GHEE-1L'    },
      { label: '500 ml',   code: 'BTL-GHEE-500ML'  },
      { label: '100 ml',   code: 'BTL-GHEE-100ML'  },
    ],
  },
  {
    product: 'Jivamrut',
    icon: '🌿',
    color: 'green',
    sizes: [
      { label: '1 Litre',  code: 'BTL-JIVA-1L'    },
    ],
  },
];

const GROUP_COLORS = {
  blue:   { header: 'bg-blue-50 text-blue-800 border-blue-200',   badge: 'blue'   },
  yellow: { header: 'bg-yellow-50 text-yellow-800 border-yellow-200', badge: 'yellow' },
  green:  { header: 'bg-green-50 text-green-800 border-green-200',  badge: 'green'  },
};

/* ── Bottles-specific table ───────────────────────────────────────────── */
function BottlesTable({ bottleItems, loading, onTransaction }) {
  // Build a quick lookup: item_code → item object
  const byCode = {};
  bottleItems.forEach(i => { byCode[i.item_code] = i; });

  let serial = 0;

  return (
    <div className="bg-white rounded-xl border border-gray-300 shadow-sm overflow-hidden">
      {/* Table header banner */}
      <div className="px-5 py-3 border-b-2 border-gray-200 flex items-center justify-between bg-amber-50">
        <div className="flex items-center gap-2">
          <span className="text-xl">🍶</span>
          <div>
            <h2 className="font-semibold text-gray-800 text-sm">Bottle Stock Register</h2>
            <p className="text-xs text-gray-400">Milk · Ghee · Jivamrut — 3 products, 6 SKUs</p>
          </div>
        </div>
        <span className="text-xs text-amber-700 bg-amber-100 border border-amber-200 px-2 py-1 rounded-full font-medium">
          Total SKUs: 6
        </span>
      </div>

      <table className="w-full text-sm border-collapse">
        <thead className="bg-gray-100 text-gray-600 text-xs uppercase">
          <tr>
            <th className="px-4 py-3 text-center border border-gray-300 w-10">Sr.</th>
            <th className="px-4 py-3 text-left   border border-gray-300">Product</th>
            <th className="px-4 py-3 text-left   border border-gray-300">Size</th>
            <th className="px-4 py-3 text-left   border border-gray-300">Item Code</th>
            <th className="px-4 py-3 text-right  border border-gray-300">Stock (bottles)</th>
            <th className="px-4 py-3 text-right  border border-gray-300">Reorder At</th>
            <th className="px-4 py-3 text-right  border border-gray-300">Unit Cost</th>
            <th className="px-4 py-3 text-center border border-gray-300">Status</th>
            <th className="px-4 py-3 text-center border border-gray-300">Action</th>
          </tr>
        </thead>
        <tbody>
          {loading ? (
            <tr>
              <td colSpan={9} className="px-4 py-10 text-center text-gray-400 border border-gray-200">
                Loading…
              </td>
            </tr>
          ) : (
            BOTTLE_GROUPS.map(group => {
              const colors = GROUP_COLORS[group.color];
              return [
                /* ── Group header row ── */
                <tr key={`hdr-${group.product}`}>
                  <td
                    colSpan={9}
                    className={`px-4 py-2 border border-gray-300 font-semibold text-sm ${colors.header}`}
                  >
                    {group.icon} {group.product} Bottles
                    <span className="ml-2 text-xs font-normal opacity-70">
                      ({group.sizes.length} size{group.sizes.length > 1 ? 's' : ''})
                    </span>
                  </td>
                </tr>,

                /* ── Data rows ── */
                ...group.sizes.map((size, sIdx) => {
                  serial += 1;
                  const item = byCode[size.code];
                  const qty       = item ? Number(item.quantity_on_hand) : 0;
                  const reorder   = item ? Number(item.reorder_level)    : 0;
                  const isLow     = qty <= reorder;
                  const unitCost  = item?.unit_cost;
                  const isEven    = sIdx % 2 === 0;

                  return (
                    <tr
                      key={size.code}
                      className={isEven ? 'bg-white hover:bg-gray-50' : 'bg-gray-50 hover:bg-gray-100'}
                    >
                      {/* Sr. No. */}
                      <td className="px-4 py-2.5 text-center text-gray-400 border border-gray-200">
                        {serial}
                      </td>

                      {/* Product name */}
                      <td className="px-4 py-2.5 font-medium text-gray-900 border border-gray-200">
                        {group.icon} {group.product}
                      </td>

                      {/* Size */}
                      <td className="px-4 py-2.5 text-gray-700 border border-gray-200">
                        {size.label}
                      </td>

                      {/* Item Code */}
                      <td className="px-4 py-2.5 text-xs font-mono text-gray-500 border border-gray-200">
                        {size.code}
                      </td>

                      {/* Stock */}
                      <td className="px-4 py-2.5 text-right font-bold border border-gray-200">
                        <span className={qty === 0 ? 'text-gray-400' : qty <= reorder ? 'text-red-600' : 'text-gray-900'}>
                          {qty}
                        </span>
                      </td>

                      {/* Reorder At */}
                      <td className="px-4 py-2.5 text-right text-gray-500 border border-gray-200">
                        {reorder}
                      </td>

                      {/* Unit Cost */}
                      <td className="px-4 py-2.5 text-right text-gray-500 border border-gray-200">
                        {unitCost ? INR(unitCost) : '—'}
                      </td>

                      {/* Status */}
                      <td className="px-4 py-2.5 text-center border border-gray-200">
                        {item ? (
                          <Badge
                            label={isLow ? 'Low Stock' : 'OK'}
                            variant={isLow ? 'red' : 'green'}
                          />
                        ) : (
                          <span className="text-xs text-gray-400">—</span>
                        )}
                      </td>

                      {/* Action */}
                      <td className="px-4 py-2.5 text-center border border-gray-200">
                        {item ? (
                          <button
                            onClick={() => onTransaction(item)}
                            className="text-xs text-primary-600 hover:text-primary-800 font-medium whitespace-nowrap"
                          >
                            + Stock
                          </button>
                        ) : (
                          <span className="text-xs text-gray-300">—</span>
                        )}
                      </td>
                    </tr>
                  );
                }),
              ];
            })
          )}

          {/* Grand total row */}
          {!loading && (
            <tr className="bg-green-50 font-semibold">
              <td colSpan={4} className="px-4 py-2.5 text-green-900 border-2 border-green-300">
                Total (all bottles)
              </td>
              <td className="px-4 py-2.5 text-right text-green-900 border-2 border-green-300">
                {BOTTLE_GROUPS.flatMap(g => g.sizes).reduce((sum, s) => {
                  const item = byCode[s.code];
                  return sum + (item ? Number(item.quantity_on_hand) : 0);
                }, 0)}
              </td>
              <td colSpan={4} className="border-2 border-green-300"></td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

/* ── Main Inventory page ──────────────────────────────────────────────── */
export default function Inventory() {
  const [items, setItems]       = useState([]);
  const [loading, setLoading]   = useState(true);
  const [showLow, setShowLow]   = useState(false);
  const [activeCategory, setActiveCategory] = useState('All');
  const [showTxn, setShowTxn]   = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  const [txnForm, setTxnForm]   = useState({ txn_type: 'Purchase', quantity: '', notes: '' });

  useEffect(() => { fetchItems(); }, [showLow]);

  const fetchItems = async () => {
    setLoading(true);
    try {
      const res = await inventoryAPI.list(showLow ? { low_stock: true } : {});
      setItems(res.data.data?.results || []);
    } catch { toast.error('Failed to load inventory.'); }
    finally { setLoading(false); }
  };

  const handleTransaction = async (e) => {
    e.preventDefault();
    try {
      await inventoryAPI.addTransaction({
        item:     selectedItem.id,
        txn_type: txnForm.txn_type,
        quantity:  +txnForm.quantity,
        notes:    txnForm.notes,
      });
      toast.success('Stock updated!');
      setShowTxn(false);
      setTxnForm({ txn_type: 'Purchase', quantity: '', notes: '' });
      fetchItems();
    } catch (err) {
      const msg = err.response?.data?.errors?.quantity?.[0] || err.response?.data?.message || 'Transaction failed.';
      toast.error(msg);
    }
  };

  const openTransaction = (item) => { setSelectedItem(item); setShowTxn(true); };

  // Client-side category filter (for the generic table)
  const visibleItems = activeCategory === 'All'
    ? items
    : items.filter(i => i.category === activeCategory);

  const bottleItems = items.filter(i => i.category === 'Bottles');
  const lowCount    = items.filter(i => i.is_low_stock).length;

  return (
    <div>
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <h1 className="text-2xl font-bold text-gray-900">📦 Inventory</h1>
        <div className="flex items-center gap-3">
          {lowCount > 0 && (
            <span className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded-full font-medium">
              ⚠ {lowCount} low-stock
            </span>
          )}
          <label className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer">
            <input type="checkbox" checked={showLow} onChange={e => setShowLow(e.target.checked)}
              className="rounded" />
            Low-stock only
          </label>
        </div>
      </div>

      {/* Category tabs */}
      <div className="flex gap-2 flex-wrap mb-5">
        {CATEGORIES.map(cat => {
          const count  = cat === 'All' ? items.length : items.filter(i => i.category === cat).length;
          const active = activeCategory === cat;
          return (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium border transition-colors ${
                active
                  ? 'bg-primary-600 text-white border-primary-600 shadow-sm'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-primary-300 hover:text-primary-700'
              }`}
            >
              <span>{CAT_ICON[cat]}</span>
              <span>{cat}</span>
              {count > 0 && (
                <span className={`text-xs px-1.5 py-0.5 rounded-full ${active ? 'bg-white/20 text-white' : 'bg-gray-100 text-gray-500'}`}>
                  {count}
                </span>
              )}
            </button>
          );
        })}
      </div>

      {/* Transaction modal */}
      {showTxn && selectedItem && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl p-6 w-full max-w-md shadow-xl">
            <h3 className="font-semibold text-gray-900 mb-1">Record Transaction</h3>
            <p className="text-sm text-gray-500 mb-4">
              {selectedItem.name} — {Number(selectedItem.quantity_on_hand).toFixed(0)} bottles on hand
            </p>
            <form onSubmit={handleTransaction} className="space-y-4">
              <select value={txnForm.txn_type}
                onChange={e => setTxnForm(f => ({ ...f, txn_type: e.target.value }))}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm">
                {['Purchase','Consumption','Adjustment','Return','Wastage'].map(t => <option key={t}>{t}</option>)}
              </select>
              <input required type="number" step="1" min="1" value={txnForm.quantity}
                onChange={e => setTxnForm(f => ({ ...f, quantity: e.target.value }))}
                placeholder="Quantity (bottles) *"
                className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm" />
              <input value={txnForm.notes}
                onChange={e => setTxnForm(f => ({ ...f, notes: e.target.value }))}
                placeholder="Notes (optional)"
                className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm" />
              <div className="flex gap-3 justify-end">
                <button type="button" onClick={() => setShowTxn(false)}
                  className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-lg">Cancel</button>
                <button type="submit"
                  className="px-4 py-2 text-sm bg-primary-600 text-white rounded-lg hover:bg-primary-700">Save</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ── BOTTLES tab: dedicated structured table ── */}
      {activeCategory === 'Bottles' ? (
        <BottlesTable
          bottleItems={bottleItems}
          loading={loading}
          onTransaction={openTransaction}
        />
      ) : (
        /* ── All other tabs: generic table ── */
        <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
          <table className="w-full text-sm">
            <thead className="bg-gray-50 text-gray-600 text-xs uppercase">
              <tr>
                <th className="px-4 py-3 text-left">Item</th>
                <th className="px-4 py-3 text-left">Category</th>
                <th className="px-4 py-3 text-right">On Hand</th>
                <th className="px-4 py-3 text-right">Reorder At</th>
                <th className="px-4 py-3 text-right">Unit Cost</th>
                <th className="px-4 py-3 text-center">Status</th>
                <th className="px-4 py-3 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {loading ? (
                <tr><td colSpan={7} className="px-4 py-8 text-center text-gray-400">Loading…</td></tr>
              ) : visibleItems.length === 0 ? (
                <tr><td colSpan={7} className="px-4 py-8 text-center text-gray-400">No items in this category</td></tr>
              ) : visibleItems.map(item => (
                <tr key={item.id} className="hover:bg-gray-50">
                  <td className="px-4 py-3">
                    <div className="font-medium">{item.name}</div>
                    <div className="text-xs text-gray-400">{item.item_code}</div>
                  </td>
                  <td className="px-4 py-3 text-gray-600">
                    <span className="mr-1">{CAT_ICON[item.category] || '📋'}</span>
                    {item.category}
                  </td>
                  <td className="px-4 py-3 text-right font-medium">
                    {Number(item.quantity_on_hand).toFixed(0)} {item.unit}s
                  </td>
                  <td className="px-4 py-3 text-right text-gray-500">
                    {Number(item.reorder_level).toFixed(0)} {item.unit}s
                  </td>
                  <td className="px-4 py-3 text-right text-gray-500">
                    {item.unit_cost ? INR(item.unit_cost) : '—'}
                  </td>
                  <td className="px-4 py-3 text-center">
                    <Badge
                      label={item.is_low_stock ? 'Low Stock' : 'OK'}
                      variant={item.is_low_stock ? 'red' : 'green'}
                    />
                  </td>
                  <td className="px-4 py-3 text-center">
                    <button onClick={() => openTransaction(item)}
                      className="text-xs text-primary-600 hover:text-primary-800 font-medium">
                      + Transaction
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
